gelu_source = """
#include <torch/extension.h>
#include <cuda_runtime.h>
#include <c10/cuda/CUDAGuard.h>
#include <math.h>
#include <stdio.h>

namespace {
// Critical constants with validation requirements
constexpr float GELU_COEF = 0.044715f;
constexpr float SQRT_2_OVER_PI = 0.7978845608028654f;  // sqrt(2/π)

// Reference values for validation (with 1e-6 tolerance)
constexpr float REF_GELU_COEF = 0.044715f;
constexpr float REF_SQRT_2_OVER_PI = 0.7978845608028654f;
constexpr float CONST_TOLERANCE = 1e-6f;

__device__ __forceinline__ bool validate_constants() {
    return (fabsf(GELU_COEF - REF_GELU_COEF) < CONST_TOLERANCE) && 
           (fabsf(SQRT_2_OVER_PI - REF_SQRT_2_OVER_PI) < CONST_TOLERANCE);
}
}

template<typename T>
__device__ T fast_tanh(T x) {
    // More accurate tanh approximation for GELU
    if (x < -4.97f) return T(-1.0f);
    if (x > 4.97f) return T(1.0f);
    T x2 = x * x;
    T a = x * (T(135135.0f) + x2 * (T(17325.0f) + x2 * (T(378.0f) + x2)));
    T b = T(135135.0f) + x2 * (T(62370.0f) + x2 * (T(3150.0f) + x2 * T(28.0f)));
    return a / b;
}

template<typename T>
__global__ void gelu_kernel(const T* __restrict__ input, T* __restrict__ output, int size, bool verify) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;

    // Validate constants in thread 0 of first block only
    if (verify && idx == 0 && blockIdx.x == 0) {
        if (!validate_constants()) {
            // Use printf for debugging (visible with CUDA_LAUNCH_BLOCKING=1)
            printf("ERROR: Critical constant validation failed! GELU_COEF=%.10f (expected %.10f)\n", 
                   GELU_COEF, REF_GELU_COEF);
        }
    }

    if (idx < size) {
        T x = input[idx];
        T x_cubed = x * x * x;
        T inner = SQRT_2_OVER_PI * (x + GELU_COEF * x_cubed);
        T tanh_val = fast_tanh<T>(inner);
        output[idx] = T(0.5f) * x * (T(1.0f) + tanh_val);
    }
}

template<>
__global__ void gelu_kernel<half>(const half* __restrict__ input, half* __restrict__ output, int size, bool verify) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;

    // Validate constants in thread 0 of first block only
    if (verify && idx == 0 && blockIdx.x == 0) {
        if (!validate_constants()) {
            printf("ERROR: Critical constant validation failed! GELU_COEF=%.10f (expected %.10f)\n", 
                   GELU_COEF, REF_GELU_COEF);
        }
    }

    if (idx < size) {
        float x = __half2float(input[idx]);
        float x_cubed = x * x * x;
        float inner = SQRT_2_OVER_PI * (x + GELU_COEF * x_cubed);
        float tanh_val = fast_tanh<float>(inner);
        output[idx] = __float2half(0.5f * x * (1.0f + tanh_val));
    }
}

// Verification kernel that computes L2 error against reference
__global__ void verify_gelu_kernel(const float* custom_output, const float* reference_output, 
                                  int size, float* max_abs_error, float* l2_error) {
    extern __shared__ float shared_mem[];
    float* max_errors = shared_mem;
    float* l2_errors = &shared_mem[blockDim.x];

    int idx = blockIdx.x * blockDim.x + threadIdx.x;

    float thread_max = 0.0f;
    float thread_l2 = 0.0f;

    if (idx < size) {
        float custom = custom_output[idx];
        float reference = reference_output[idx];
        float diff = custom - reference;
        thread_max = fabsf(diff);
        thread_l2 = diff * diff;
    }

    max_errors[threadIdx.x] = thread_max;
    l2_errors[threadIdx.x] = thread_l2;
    __syncthreads();

    // Parallel reduction for max
    for (int stride = blockDim.x / 2; stride > 0; stride >>= 1) {
        if (threadIdx.x < stride) {
            max_errors[threadIdx.x] = fmaxf(max_errors[threadIdx.x], max_errors[threadIdx.x + stride]);
            l2_errors[threadIdx.x] += l2_errors[threadIdx.x + stride];
        }
        __syncthreads();
    }

    if (threadIdx.x == 0) {
        atomicMaxf(max_abs_error, max_errors[0]);
        atomicAdd(l2_error, l2_errors[0]);
    }
}

__device__ void atomicMaxf(float* address, float val) {
    int* address_as_i = (int*)address;
    int old = *address_as_i;
    int assumed;
    do {
        assumed = old;
        if (__int_as_float(assumed) >= val) {
            break;
        }
        old = atomicCAS(address_as_i, assumed, __float_as_int(val));
    } while (assumed != old);
}

torch::Tensor gelu_cuda(torch::Tensor input, bool verify_constants) {
    at::cuda::CUDAGuard guard(input.device());
    auto size = input.numel();
    auto output = torch::empty_like(input);

    const int block_size = 256;
    const int num_blocks = (size + block_size - 1) / block_size;

    AT_DISPATCH_FLOATING_TYPES_AND_HALF(input.scalar_type(), "gelu_cuda", [&] {
        gelu_kernel<scalar_t><<<num_blocks, block_size>>>(
            input.data_ptr<scalar_t>(),
            output.data_ptr<scalar_t>(),
            size,
            verify_constants
        );
    });

    return output;
}

std::pair<torch::Tensor, torch::Tensor> verify_gelu_cuda(torch::Tensor input) {
    at::cuda::CUDAGuard guard(input.device());

    // Always compute reference using PyTorch's native GELU
    auto reference = torch::nn::functional::gelu(input, torch::nn::functional::GELUFuncOptions().approximate("tanh"));
    auto custom = gelu_cuda(input, false);

    // Convert to float32 for accurate error computation
    auto custom_f32 = custom.to(torch::kFloat32);
    auto reference_f32 = reference.to(torch::kFloat32);

    auto max_error = torch::zeros({1}, torch::TensorOptions().dtype(torch::kFloat32).device(input.device()));
    auto l2_error = torch::zeros({1}, torch::TensorOptions().dtype(torch::kFloat32).device(input.device()));

    const int block_size = 256;
    const int num_blocks = (input.numel() + block_size - 1) / block_size;
    const size_t shared_mem = 2 * block_size * sizeof(float);

    verify_gelu_kernel<<<num_blocks, block_size, shared_mem>>>(
        custom_f32.data_ptr<float>(),
        reference_f32.data_ptr<float>(),
        input.numel(),
        max_error.data_ptr<float>(),
        l2_error.data_ptr<float>()
    );

    // Compute RMS error
    auto rms_error = torch::sqrt(l2_error / input.numel());

    return std::make_pair(max_error, rms_error);
}
